              !!window._GE90A320NEO_paused ||
              !!window._GE90A320NEO_persistentlyMuted;  // Add persistent mute
            window._GE90A320NEO_muted = effectiveMuted;
            // Force mute all HTML5 audio elements if persistently muted
            if (window._GE90A320NEO_persistentlyMuted) {
              forceMuteAllAudio();
            }
            // Volume is now handled by the single shared GE-Ultimate volume slider (see bottom of file)
