        if (!layer) return;

// -----------------------------
// BUZZSAW LOGIC
// -----------------------------
if (k === "buzzsaw") {
    const buzz = window.GE90A330_layers?.buzzsaw;
    if (!buzz) return;

    const start = 0.65;
    const end   = 1.00;

    let amt = 0;
    if (t > start) {
        amt = (t - start) / (end - start);
        amt = Math.pow(Math.min(1, Math.max(0, amt)), 1.4);
    }

    // Apply altitude-based gain
    window.applyBuzzsawAltitudeAttenuation_A330(buzz, amt, geCtx);

    // Pitch (multiplied by proximity pitch shift)
    const proximityPitch = window._GE90A330_proximityPitchMult || 1.0;
    const rate = (0.78 + amt * 0.20) * proximityPitch;
    if (buzz.src?.playbackRate) {
        buzz.src.playbackRate.setTargetAtTime(rate, geCtx.currentTime, 0.05);
    }

    return;
}

    // -----------------------------
    // NORMAL ENGINE LAYERS
