// RAIN SOUND SYSTEM (cockpit-only, fixed volume, GE90 interior chain)
// -------------------------------------------------------------
(function setupRainSound(){
    const ctx = window._GE90A330_audioCtx;
    const finalMaster = window._GE90A330_finalMaster || window._GE90A330_master;
    if (!ctx || !finalMaster) return;

    const RAIN_URL =
        "https://raw.githubusercontent.com/ChristianPilotAlex003/GeoFS-Airbus-A320-Sound-Pack/main/Weather_6.wav";

    let rainBuf = null;
    let rainSrc = null;
    let rainGain = null;

    // -----------------------------
    // Load rain buffer
    // -----------------------------
    async function loadRainBuffer(){
        if (rainBuf) return rainBuf;
        try {
            const r = await fetch(RAIN_URL, { mode: "cors" });
            const ab = await r.arrayBuffer();
            rainBuf = await ctx.decodeAudioData(ab);
            console.log("[GE90 Rain] buffer loaded");
        } catch(e){
            console.warn("[GE90 Rain] load failed", e);
        }
        return rainBuf;
    }

    // -----------------------------
    // Start rain loop
    // -----------------------------
    function startRain(){
        if (rainSrc || !rainBuf) return;

        rainSrc = ctx.createBufferSource();
        rainSrc.buffer = rainBuf;
        rainSrc.loop = true;
        rainSrc._GE90_TAG = true;

        rainGain = ctx.createGain();
        rainGain.gain.value = 0;
        rainGain._GE90_TAG = true;

        rainSrc.connect(rainGain);
        rainGain.connect(finalMaster);

        // register as interior node if array exists
        if (Array.isArray(window._GE90A330_interior_nodes)) {
            window._GE90A330_interior_nodes.push(rainGain);
        }

        rainSrc.start(0);

        console.log("[GE90 Rain] started");
    }

    // -----------------------------
    // Stop rain loop
    // -----------------------------
    function stopRain(){
        if (!rainSrc) return;

        try {
            rainGain.gain.setTargetAtTime(0, ctx.currentTime, 0.25);
            setTimeout(() => {
                try { rainSrc.stop(); } catch(e){}
                rainSrc = null;
                rainGain = null;
            }, 400);
            console.log("[GE90 Rain] stopped");
        } catch(e){}
    }

    // -----------------------------
    // Rain ON/OFF detector
    // -----------------------------
    function isRaining(){
        try {
            const p = geofs?.fx?.precipitation;
            if (!p) return false;
            return p.visible === true && p.type === "rain";
        } catch(e){
            return false;
        }
    }

    // -----------------------------
    // Cockpit view detector
    // -----------------------------
    function isCockpitView(){
        try {
            const v = String(geofs.camera.currentView || "").toLowerCase();
            return (
                v.includes("cockpit") ||
                v.includes("pilot") ||
                v.includes("interior")
            );
        } catch(e){
            return false;
        }
    }

    // -----------------------------
    // Main controller
    // -----------------------------
    setInterval(async () => {
        try {
            const cockpitView = isCockpitView();

            const muted =
                window._GE90A330_persistentlyMuted ||
                window._GE90A330_userMuted ||
                window._GE90A330_paused ||
                window._GE90A330_muted ||
                window._GE90A330_siteMuted;

            if (!rainBuf) await loadRainBuffer();

            const raining = isRaining();

            if (cockpitView && !muted && raining) {
                startRain();

                if (rainGain) {
                    const targetGain = 0.35; // adjust to taste
                    rainGain.gain.setTargetAtTime(targetGain, ctx.currentTime, 0.20);
                }
            } else {
                stopRain();
            }

        } catch(e){
            console.warn("[GE90 Rain] controller error", e);
        }
    }, 200);

    console.log("[GE90 Rain] rain system initialized (fixed volume, interior chain)");
})();

        // -------------------------
        // Site mute detection
        // -------------------------
        function detectSiteMuted(){
          try {
            if (window.Howler && typeof window.Howler._muted !== 'undefined')
              return !!window.Howler._muted;

            const medias = Array.from(document.querySelectorAll('audio,video'));
            const userMutedMedias = medias.filter(m => !m._GE90_FORCED_MUTE_BY_PACK);
            if (!userMutedMedias.length) return false;
            return userMutedMedias.every(m => m.muted || m.volume === 0);
          } catch(e){
            return false;
          }
        }
// -----------------------------
// Engine on/off toggle sound (state-based, cockpit only)
// -----------------------------
(function(){
  const TOGGLE_SOUND_URL = "https://raw.githubusercontent.com/ChristianPilotAlex003/GeoFS-B777-300ER-Sound-Pack-Official/main/Master_19.wav";
  const POLL_MS = 120;
  const DEBOUNCE_MS = 500;
  const SPAWN_PROTECT_MS = window.SPAWN_PROTECTION_MS || 5000;

  let _et_buf = null;
  let _et_poll = null;
  let _et_lastState = null;
  let _et_lastToggle = 0;

  async function _et_load(){
    if (_et_buf) return _et_buf;
    try {
      const r = await fetch(TOGGLE_SOUND_URL, { mode: 'cors' });
      const ab = await r.arrayBuffer();
      _et_buf = await ctx.decodeAudioData(ab);
      console.log("[GE90 EngineToggle] buffer loaded");
    } catch (e) {
      console.warn("[GE90 EngineToggle] load failed", e);
    }
    return _et_buf;
  }

  function _et_playOnce(gain = 0.6){
    try {
      if (!ctx || !_et_buf) return;

      // Only play in cockpit / jump seat
      const view = (typeof getViewType === 'function') ? getViewType() : (window._GE90A330_viewType || 'exterior');
      if (view !== 'cockpit' && !/jump/i.test(view) && view !== 'vc') return;

      // Create a clean one-shot that avoids jitter and heavy EQ
      const src = ctx.createBufferSource();
      src.buffer = _et_buf;
      src.loop = false;
      src.playbackRate.setValueAtTime(1.0, ctx.currentTime);
      src._GE90_TAG = true;

      const g = ctx.createGain();
      g.gain.setValueAtTime(gain, ctx.currentTime);
      g._GE90_TAG = true;

      src.connect(g);

      // Prefer connecting to finalMaster (post-processing) so the sound is not altered by interior EQ chain
      // finalMaster exists in your script as window._GE90A330_finalMaster; fallback to master
      const outNode = window._GE90A330_finalMaster || master || ctx.destination;
      g.connect(outNode);

      src.start(ctx.currentTime);

      // Cleanup after playback
      const cleanupMs = Math.round((_et_buf.duration || 2) * 1000 + 200);
      setTimeout(()=>{
        try { src.stop(); } catch(e){}
        try { src.disconnect(); } catch(e){}
        try { g.disconnect(); } catch(e){}
      }, cleanupMs);
    } catch (e) {
      console.warn("[GE90 EngineToggle] play error", e);
    }
  }

  // Robust read of engine boolean state (tries multiple properties)
  function _readEngineState(){
    try {
      const inst = window.geofs?.aircraft?.instance;
      if (!inst) return null;
      const engine = inst.engine || inst.engines?.[0] || null;
      if (!engine) return null;

      // Candidate boolean/numeric properties
      const candidates = [
        engine.on,
        engine.running,
        engine.isRunning,
        engine.master,
        engine.starter,
        engine.starterOn,
        engine.runningState,
        engine.state
      ];

      for (const c of candidates) {
        if (typeof c === 'boolean') return c;
        if (typeof c === 'number') return c > 0;
        if (typeof c === 'string' && (c === 'on' || c === 'running' || c === '1')) return true;
      }

      // Fallback: if rpm exists, treat rpm > small threshold as running
      if (typeof engine.rpm === 'number' && !isNaN(engine.rpm)) {
        return engine.rpm > 50;
      }

      return null;
    } catch(e){
      return null;
    }
  }

  function _et_start(){
    if (_et_poll) return;
    _et_poll = setInterval(async ()=>{
      try {
        const now = performance.now();
        const timeSinceSpawn = (window._GE90A330_spawnTime) ? (now - window._GE90A330_spawnTime) : 0;
        const spawnProtected = timeSinceSpawn < SPAWN_PROTECT_MS;

        const state = _readEngineState();
        if (state === null) return;

        // initialize
        if (_et_lastState === null) {
          _et_lastState = state;
          return;
        }

        // Detect change (toggle)
        if (state !== _et_lastState && (now - _et_lastToggle) > DEBOUNCE_MS && !spawnProtected) {
          _et_lastToggle = now;
          await _et_load();
          // Play only once per toggle
          _et_playOnce(0.4);
          console.log("[GE90 EngineToggle] engine toggled ->", state ? "ON" : "OFF");
        }

        _et_lastState = state;
      } catch(e){
        console.warn("[GE90 EngineToggle] poll error", e);
      }
    }, POLL_MS);
    console.log("[GE90 EngineToggle] polling started");
  }

  // Wait for audio context and start
  (function waitForReady(){
    if (typeof ctx !== 'undefined' && ctx && (window._GE90A330_finalMaster || master)) {
      _et_start();
    } else {
      setTimeout(waitForReady, 250);
    }
  })();

  // Test helper
  window.GE90A330_testEngineToggleSound = async function(){
    await _et_load();
    _et_playOnce(0.6);
  };
})();

        // -------------------------------------------------------------
