(function setupSpoilerClick(){
    const ctx = window._GE90A350_audioCtx;
    const master = window._GE90A350_master;
    if (!ctx || !master) return;

    const SPOILER_URL = "https://raw.githubusercontent.com/ChristianPilotAlex003/GeoFS-B777-Sound-Pack-Official/main/Master_10.wav";

    let spoilerBuf = null;
    let lastState = 0; // 0 = retracted, 1 = mid, 2 = fully deployed
    let debounce = 0;

    async function loadSpoilerBuffer(){
        if (spoilerBuf) return spoilerBuf;
        try {
            const r = await fetch(SPOILER_URL, { mode: "cors" });
            const ab = await r.arrayBuffer();
            spoilerBuf = await ctx.decodeAudioData(ab);
            console.log("[GE90 Spoiler] buffer loaded");
        } catch(e){
            console.warn("[GE90 Spoiler] load failed", e);
        }
        return spoilerBuf;
    }

    function playSpoilerClick(){
        if (!spoilerBuf) return;

        const view = (typeof getViewType === "function")
            ? getViewType()
            : (window._GE90A350_viewType || "exterior");

        if (view !== "cockpit" && view !== "jumpseat") return;

        const src = ctx.createBufferSource();
        src.buffer = spoilerBuf;
        src._GE90_TAG = true;

        const g = ctx.createGain();
        g.gain.value = 0.63; // Slightly increased from 0.55 (spoiler click)
        g._GE90_TAG = true;

        src.connect(g);
        g.connect(master);
        src.start();
    }

setInterval(async () => {
    const now = performance.now();
    const val = geofs?.animation?.values?.airbrakesPosition;

    if (typeof val !== "number") return;

    // Two meaningful states:
    // 0 = retracted (0 → 0.05)
    // 1 = deployed (0.95 → 1)
    let currentState;

    if (val > 0.05) {
        currentState = 1; // spoilers moving or deployed
    } else {
        currentState = 0; // spoilers retracted or nearly retracted
    }

    // Only click when crossing the FIRST threshold of movement
    if (currentState !== lastState && (now - debounce) > 200) {
        debounce = now;
        await loadSpoilerBuffer();
        playSpoilerClick();
        console.log("[GE90 Spoiler] click (state change)", lastState, "→", currentState);
    }

    lastState = currentState;

}, 80);

    console.log("[GE90 Spoiler] dual-edge spoiler click initialized");
})();
