            let interiorBlend = EXTERIOR_INTERIOR_BLEND;
            if (!effectiveMuted) {
              if (viewType === "cockpit") interiorBlend = COCKPIT_INTERIOR_BLEND;
              else if (viewType === "wing2") interiorBlend = WING2_INTERIOR_BLEND;
            }

            const exteriorBlend = 1 - interiorBlend;

            extGain.gain.setTargetAtTime(exteriorBlend, ctx.currentTime, 0.15);
