          async function playOneShot(url, gain = 1.0){
            try {
              if (performance.now() - startTime < STARTUP_SUPPRESS_MS) return;

              const buf = await fetchDecode(url);
              const src = geCtx.createBufferSource();
              const g = geCtx.createGain();
              g.gain.value = gain;

              src.buffer = buf;
              src._GE90_TAG = true;
              g._GE90_TAG = true;

              src.connect(g);
              g.connect(master);
              src.start(0);

              if (url === STARTUP_URL) {
                try {
                  if (window._GE90B777_startupSrc) {
                    try { window._GE90B777_startupSrc.stop(); } catch(e){}
                  }
                } catch(e){}
                window._GE90B777_startupSrc = src;
              }
            } catch(e){
              console.warn('[GE90] one-shot failed', url, e);
            }
          }
