// ---------------------------------------------------------------
// Popup control logic
// ---------------------------------------------------------------
if (typeof window.liveATCPopup === 'undefined') window.liveATCPopup = null;

// Closes whatever ATC popup is currently open, and is self-healing: if this
// panel ever gets rebuilt while a popup is still open (e.g. the page
// re-injects this script, or the panel is force-recreated), the tracked
// `window.liveATCPopup` reference gets reset to null even though a real
// popup window is still sitting open in the browser. Relying on that
// reference alone is exactly what causes "Close ATC" to silently do
// nothing, and "Open ATC" to fail to close the previous popup.
//
// Fix: if our tracked reference has nothing to close, fall back to
// re-acquiring the window by its name ("liveatc") instead. Calling
// window.open('', 'liveatc') returns a handle to any existing window
// already registered under that name (without navigating it away) — this
// works even when our own JS reference was lost, because the browser
// itself (not our script) is the source of truth for the name-to-window
// mapping. If nothing is open, this creates a blank throwaway popup,
// which we immediately close so nothing stray is left behind.
function closeATCPopup(){
    let closedSomething = false;

    try {
        if (window.liveATCPopup && !window.liveATCPopup.closed) {
            window.liveATCPopup.close();
            closedSomething = true;
        }
    } catch(e){}

    if (!closedSomething) {
        try {
            const handle = window.open('', 'liveatc');
            if (handle && !handle.closed) handle.close();
        } catch(e){}
    }

    window.liveATCPopup = null;
}

function openATCPopup(url) {
    // Always close whatever is currently open under this name first, via
    // the self-healing helper above, so a stale/lost reference never
    // leaves an orphaned popup open behind a new one.
    closeATCPopup();

    // Open new popup
    window.liveATCPopup = window.open(
        url,
        "liveatc",
        "width=420,height=360,menubar=no,toolbar=no"
    );

    if (!window.liveATCPopup || window.liveATCPopup.closed) {
        alert("Popup blocked! Please allow popups for GeoFS.");
    }
}

