    // the instant it's created so callouts are never silently muted,
    // regardless of hosting domain or future changes to that guard.
    // =====================================================================
    function geTagAudio(a) {
        try { a.dataset.geofsAllow = 'true'; a.dataset.gpwsAllow = 'true'; } catch (e) {}
        return a;
    }

